import mongoose from 'mongoose';
import { createClient } from 'redis';
import logger from '../utils/logger';

export class DatabaseConfig {
  private static instance: DatabaseConfig;
  private redisClient: ReturnType<typeof createClient>;

  private constructor() {
    this.redisClient = createClient({
      url: process.env.REDIS_URL || 'redis://localhost:6379',
    });

    this.redisClient.on('error', (err) => {
      logger.error('Redis Client Error', err);
    });
  }

  static getInstance(): DatabaseConfig {
    if (!DatabaseConfig.instance) {
      DatabaseConfig.instance = new DatabaseConfig();
    }
    return DatabaseConfig.instance;
  }

  async connectMongoDB(): Promise<void> {
    try {
      const mongoURI = process.env.MONGODB_URI || 'mongodb://localhost:27017/auth-service';

      await mongoose.connect(mongoURI, {
        // Mongoose 8.x uses new URL parser and unified topology by default
      });

      logger.info('MongoDB connected successfully');

      mongoose.connection.on('error', (err) => {
        logger.error('MongoDB connection error:', err);
      });

      mongoose.connection.on('disconnected', () => {
        logger.warn('MongoDB disconnected. Attempting to reconnect...');
      });
    } catch (error) {
      logger.error('MongoDB connection failed:', error);
      process.exit(1);
    }
  }

  async connectRedis(): Promise<void> {
    try {
      await this.redisClient.connect();
      logger.info('Redis connected successfully');
    } catch (error) {
      logger.error('Redis connection failed:', error);
      // Don't exit - Redis is optional for caching
    }
  }

  getRedisClient() {
    return this.redisClient;
  }

  async disconnect(): Promise<void> {
    await mongoose.disconnect();
    await this.redisClient.quit();
    logger.info('Database connections closed');
  }
}

export default DatabaseConfig.getInstance();
