// src/config/jwt.ts

import jwt from 'jsonwebtoken';
import { ITokenPayload, ITokenPair } from '../types/auth.types';
import logger from '../utils/logger';

export class JWTConfig {
  private static instance: JWTConfig;
  private accessSecret: string;
  private refreshSecret: string;
  private accessExpiry: string;
  private refreshExpiry: string;

  private constructor() {
    this.accessSecret = process.env.JWT_ACCESS_SECRET || 'default-access-secret';
    this.refreshSecret = process.env.JWT_REFRESH_SECRET || 'default-refresh-secret';
    this.accessExpiry = process.env.JWT_ACCESS_EXPIRY || '15m';
    this.refreshExpiry = process.env.JWT_REFRESH_EXPIRY || '7d';
  }

  static getInstance(): JWTConfig {
    if (!JWTConfig.instance) {
      JWTConfig.instance = new JWTConfig();
    }
    return JWTConfig.instance;
  }

  generateTokenPair(payload: Omit<ITokenPayload, 'type'>): ITokenPair {
    const accessToken = this.generateAccessToken(payload);
    const refreshToken = this.generateRefreshToken(payload);

    return {
      accessToken,
      refreshToken,
      expiresIn: this.parseExpiryToSeconds(this.accessExpiry),
    };
  }

  generateAccessToken(payload: Omit<ITokenPayload, 'type'>): string {
    const tokenPayload: ITokenPayload = {
      ...payload,
      type: 'access',
    };

    return jwt.sign(tokenPayload, this.accessSecret, {
      expiresIn: this.accessExpiry,
    });
  }

  generateRefreshToken(payload: Omit<ITokenPayload, 'type'>): string {
    const tokenPayload: ITokenPayload = {
      ...payload,
      type: 'refresh',
    };

    return jwt.sign(tokenPayload, this.refreshSecret, {
      expiresIn: this.refreshExpiry,
    });
  }

  verifyAccessToken(token: string): ITokenPayload | null {
    try {
      const decoded = jwt.verify(token, this.accessSecret) as ITokenPayload;

      if (decoded.type !== 'access') {
        logger.warn('Invalid token type for access token verification');
        return null;
      }

      return decoded;
    } catch (error) {
      if (error instanceof jwt.TokenExpiredError) {
        logger.warn('Access token expired');
      } else if (error instanceof jwt.JsonWebTokenError) {
        logger.warn('Invalid access token');
      }
      return null;
    }
  }

  verifyRefreshToken(token: string): ITokenPayload | null {
    try {
      const decoded = jwt.verify(token, this.refreshSecret) as ITokenPayload;

      if (decoded.type !== 'refresh') {
        logger.warn('Invalid token type for refresh token verification');
        return null;
      }

      return decoded;
    } catch (error) {
      if (error instanceof jwt.TokenExpiredError) {
        logger.warn('Refresh token expired');
      } else if (error instanceof jwt.JsonWebTokenError) {
        logger.warn('Invalid refresh token');
      }
      return null;
    }
  }

  private parseExpiryToSeconds(expiry: string): number {
    const match = expiry.match(/^(\d+)([smhd])$/);
    if (!match) return 900; // Default 15 minutes

    const value = parseInt(match[1]);
    const unit = match[2];

    switch (unit) {
      case 's': return value;
      case 'm': return value * 60;
      case 'h': return value * 3600;
      case 'd': return value * 86400;
      default: return 900;
    }
  }
}

export default JWTConfig.getInstance();
