// src/services/token.service.ts

import { v4 as uuidv4 } from 'uuid';
import jwtConfig from '../config/jwt';
import User from '../models/user.model';
import { ITokenPayload, ITokenPair } from '../types/auth.types';
import logger from '../utils/logger';
import { AppError } from '../utils/errors';

export class TokenService {
  private static instance: TokenService;

  static getInstance(): TokenService {
    if (!TokenService.instance) {
      TokenService.instance = new TokenService();
    }
    return TokenService.instance;
  }

  async generateTokens(user: any): Promise<ITokenPair> {
    const payload: Omit<ITokenPayload, 'type'> = {
      userId: user._id.toString(),
      email: user.email,
      role: user.role,
    };

    const tokens = jwtConfig.generateTokenPair(payload);

    // Store refresh token in user document
    await User.findByIdAndUpdate(user._id, {
      $push: { refreshTokens: tokens.refreshToken },
    });

    return tokens;
  }

  async refreshTokens(refreshToken: string): Promise<ITokenPair> {
    // Verify the refresh token
    const decoded = jwtConfig.verifyRefreshToken(refreshToken);
    if (!decoded) {
      throw new AppError('Invalid or expired refresh token', 401);
    }

    // Find user and check if refresh token exists
    const user = await User.findById(decoded.userId);
    if (!user || !user.isActive) {
      throw new AppError('User not found or inactive', 401);
    }

    // Check if refresh token is in user's stored tokens
    const tokenIndex = user.refreshTokens.indexOf(refreshToken);
    if (tokenIndex === -1) {
      // Possible token reuse attack - invalidate all tokens
      await this.invalidateAllUserTokens(user._id.toString());
      throw new AppError('Refresh token has been revoked', 401);
    }

    // Remove old refresh token
    user.refreshTokens.splice(tokenIndex, 1);

    // Generate new tokens
    const payload: Omit<ITokenPayload, 'type'> = {
      userId: user._id.toString(),
      email: user.email,
      role: user.role,
    };

    const tokens = jwtConfig.generateTokenPair(payload);

    // Store new refresh token
    user.refreshTokens.push(tokens.refreshToken);
    await user.save();

    return tokens;
  }

  async revokeRefreshToken(userId: string, refreshToken: string): Promise<void> {
    await User.findByIdAndUpdate(userId, {
      $pull: { refreshTokens: refreshToken },
    });
  }

  async invalidateAllUserTokens(userId: string): Promise<void> {
    await User.findByIdAndUpdate(userId, {
      $set: { refreshTokens: [] },
    });
    logger.info(`All tokens invalidated for user ${userId}`);
  }

  async verifyAccessToken(token: string): Promise<ITokenPayload | null> {
    return jwtConfig.verifyAccessToken(token);
  }
}

export default TokenService.getInstance();
