// src/services/auth.service.ts

import User from '../models/user.model';
import tokenService from './token.service';
import {
  IUserCreate,
  IUserLogin,
  IAuthResponse,
  UserRole,
} from '../types/auth.types';
import logger from '../utils/logger';
import { AppError } from '../utils/errors';

export class AuthService {
  private static instance: AuthService;

  static getInstance(): AuthService {
    if (!AuthService.instance) {
      AuthService.instance = new AuthService();
    }
    return AuthService.instance;
  }

  async register(userData: IUserCreate): Promise<IAuthResponse> {
    // Check if user already exists
    const existingUser = await User.findOne({ email: userData.email });
    if (existingUser) {
      throw new AppError('Email already registered', 409);
    }

    // Create new user
    const user = new User({
      email: userData.email,
      password: userData.password,
      firstName: userData.firstName,
      lastName: userData.lastName,
      role: userData.role || UserRole.CUSTOMER,
    });

    await user.save();

    // Generate tokens
    const tokens = await tokenService.generateTokens(user);

    logger.info(`New user registered: ${user.email}`);

    return {
      user: {
        id: user._id.toString(),
        email: user.email,
        firstName: user.firstName,
        lastName: user.lastName,
        role: user.role,
      },
      tokens,
    };
  }

  async login(credentials: IUserLogin): Promise<IAuthResponse> {
    // Find user with password field
    const user = await User.findOne({ email: credentials.email }).select('+password');

    if (!user) {
      logger.warn(`Login attempt for non-existent user: ${credentials.email}`);
      throw new AppError('Invalid email or password', 401);
    }

    // Check if account is locked
    if (user.isLocked()) {
      const lockTimeRemaining = Math.ceil(
        (user.lockUntil!.getTime() - Date.now()) / 1000 / 60
      );
      throw new AppError(
        `Account locked. Try again in ${lockTimeRemaining} minutes`,
        423
      );
    }

    // Verify password
    const isPasswordValid = await user.comparePassword(credentials.password);

    if (!isPasswordValid) {
      await user.incrementLoginAttempts();
      const attemptsRemaining = 
        parseInt(process.env.MAX_LOGIN_ATTEMPTS || '5') - user.loginAttempts;

      logger.warn(`Failed login attempt for ${user.email}. ${attemptsRemaining} attempts remaining`);

      if (attemptsRemaining <= 0) {
        throw new AppError('Account locked due to too many failed attempts', 423);
      }

      throw new AppError(`Invalid email or password. ${attemptsRemaining} attempts remaining`, 401);
    }

    // Reset login attempts on successful login
    await user.resetLoginAttempts();

    // Update last login
    user.lastLogin = new Date();
    await user.save();

    // Generate tokens
    const tokens = await tokenService.generateTokens(user);

    logger.info(`User logged in: ${user.email}`);

    return {
      user: {
        id: user._id.toString(),
        email: user.email,
        firstName: user.firstName,
        lastName: user.lastName,
        role: user.role,
      },
      tokens,
    };
  }

  async logout(userId: string, refreshToken: string): Promise<void> {
    await tokenService.revokeRefreshToken(userId, refreshToken);
    logger.info(`User logged out: ${userId}`);
  }

  async refreshToken(refreshToken: string): Promise<IAuthResponse> {
    const tokens = await tokenService.refreshTokens(refreshToken);

    // Get user info
    const decoded = await tokenService.verifyAccessToken(tokens.accessToken);
    if (!decoded) {
      throw new AppError('Failed to verify new access token', 500);
    }

    const user = await User.findById(decoded.userId);
    if (!user) {
      throw new AppError('User not found', 404);
    }

    return {
      user: {
        id: user._id.toString(),
        email: user.email,
        firstName: user.firstName,
        lastName: user.lastName,
        role: user.role,
      },
      tokens,
    };
  }

  async getProfile(userId: string) {
    const user = await User.findById(userId);
    if (!user) {
      throw new AppError('User not found', 404);
    }

    return {
      id: user._id.toString(),
      email: user.email,
      firstName: user.firstName,
      lastName: user.lastName,
      role: user.role,
      createdAt: user.createdAt,
      lastLogin: user.lastLogin,
    };
  }

  async changePassword(
    userId: string,
    currentPassword: string,
    newPassword: string
  ): Promise<void> {
    const user = await User.findById(userId).select('+password');
    if (!user) {
      throw new AppError('User not found', 404);
    }

    const isPasswordValid = await user.comparePassword(currentPassword);
    if (!isPasswordValid) {
      throw new AppError('Current password is incorrect', 401);
    }

    user.password = newPassword;
    await user.save();

    // Invalidate all existing tokens for security
    await tokenService.invalidateAllUserTokens(userId);

    logger.info(`Password changed for user: ${user.email}`);
  }
}

export default AuthService.getInstance();
