// src/middleware/auth.middleware.ts

import { Response, NextFunction } from 'express';
import tokenService from '../services/token.service';
import { IAuthenticatedRequest, UserRole } from '../types/auth.types';
import { AppError } from '../utils/errors';

export class AuthMiddleware {
  /**
   * Authenticate request - verifies JWT access token
   */
  static authenticate = async (
    req: IAuthenticatedRequest,
    res: Response,
    next: NextFunction
  ): Promise<void> => {
    try {
      const authHeader = req.headers.authorization;

      if (!authHeader || !authHeader.startsWith('Bearer ')) {
        throw new AppError('No token provided', 401);
      }

      const token = authHeader.split(' ')[1];
      const decoded = await tokenService.verifyAccessToken(token);

      if (!decoded) {
        throw new AppError('Invalid or expired token', 401);
      }

      req.user = decoded;
      next();
    } catch (error) {
      next(error);
    }
  };

  /**
   * Authorize by role - checks if user has required role
   */
  static authorize = (...roles: UserRole[]) => {
    return (req: IAuthenticatedRequest, res: Response, next: NextFunction): void => {
      if (!req.user) {
        throw new AppError('Authentication required', 401);
      }

      if (!roles.includes(req.user.role)) {
        throw new AppError('Insufficient permissions', 403);
      }

      next();
    };
  };

  /**
   * Optional authentication - doesn't fail if no token
   */
  static optionalAuth = async (
    req: IAuthenticatedRequest,
    res: Response,
    next: NextFunction
  ): Promise<void> => {
    try {
      const authHeader = req.headers.authorization;

      if (authHeader && authHeader.startsWith('Bearer ')) {
        const token = authHeader.split(' ')[1];
        const decoded = await tokenService.verifyAccessToken(token);

        if (decoded) {
          req.user = decoded;
        }
      }
    } catch (error) {
      // Silently continue without authentication
    }

    next();
  };
}
